#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[1] - y[1];
}

int main() {
    int N;
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        int K, M;
        scanf("%d %d", &K, &M);
        int events[K][2];
        for (int j = 0; j < K; j++) {
            scanf("%d %d", &events[j][0], &events[j][1]);
        }
        int participations[M][K * 2];
        for (int j = 0; j < M; j++) {
            int D;
            scanf("%d", &D);
            for (int k = 0; k < D; k++) {
                scanf("%d %d", &participations[j][k * 2], &participations[j][k * 2 + 1]);
            }
        }
        qsort(events, K, sizeof(events[0]), compare);
        int beds = 0;
        int last_end = 0;
        for (int j = 0; j < K; j++) {
            int start = events[j][0];
            int end = events[j][1];
            if (start >= last_end) {
                last_end = end;
            } else {
                beds++;
                last_end = end;
            }
        }
        printf("Case %d: %d\n", i + 1, beds);
    }
    return 0;
}

