struct Event {
    int start;
    int end;
};

bool compare(const Event &a, const Event &b) {
    return a.end < b.end;
}

int main() {
    int N;
    cin >> N;
    for (int i = 0; i < N; i++) {
        int K, M;
        cin >> K >> M;
        Event events[K];
        for (int j = 0; j < K; j++) {
            cin >> events[j].start >> events[j].end;
        }
        sort(events, events + K, compare);
        int participations[M][K * 2];
        for (int j = 0; j < M; j++) {
            int D;
            cin >> D;
            for (int k = 0; k < D; k++) {
                cin >> participations[j][k * 2] >> participations[j][k * 2 + 1];
            }
        }
        int beds = 0;
        int last_end = 0;
        for (int j = 0; j < K; j++) {
            int start = events[j].start;
            int end = events[j].end;
            if (start >= last_end) {
                last_end = end;
            } else {
                beds++;
                last_end = end;
            }
        }
        cout << "Case " << i + 1 << ": " << beds << endl;
    }
    return 0;
}

