import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        for (int i = 0; i < N; i++) {
            int K = scanner.nextInt();
            int M = scanner.nextInt();
            int[][] events = new int[K][2];
            for (int j = 0; j < K; j++) {
                events[j][0] = scanner.nextInt();
                events[j][1] = scanner.nextInt();
            }
            int[][] participations = new int[M][K * 2];
            for (int j = 0; j < M; j++) {
                int D = scanner.nextInt();
                for (int k = 0; k < D; k++) {
                    participations[j][k * 2] = scanner.nextInt();
                    participations[j][k * 2 + 1] = scanner.nextInt();
                }
            }
            Arrays.sort(events, (a, b) -> a[1] - b[1]);
            int beds = 0;
            int last_end = 0;
            for (int j = 0; j < K; j++) {
                int start = events[j][0];
                int end = events[j][1];
                if (start >= last_end) {
                    last_end = end;
                } else {
                    beds++;
                    last_end = end;
                }
            }
            System.out.println("Case " + (i + 1) + ": " + beds);
        }
    }
}

